        for (let i = 0; i < this.dataBook.length; i++) {
          total5 += this.dataBook[i].value;
        }

        for (let i = 0; i < this.dataBook.length; i++) {
          this.dataBook[i].value = Math.round((this.dataBook[i].value / total5 * 100).toFixed(2)) + '%';
        }
